import './index.css';

import {
  useEffect,
  useState
} from 'react';

import {
  getNotes
} from '../../../services/noteService';

function NotesList() {

  const [notes, setNotes] =
    useState([]);

  useEffect(() => {

    loadNotes();

  }, []);

  const loadNotes =
    async () => {

    try {

      const data =
        await getNotes();

      setNotes(data);

    } catch (error) {

      console.log(error);

    }

  };

  return (

    <div className="notes-container">

      <h2>
        Coordinator Notes
      </h2>

      {

        notes.length > 0
        ? (

          notes.map((note) => (

            <div
              key={note.id}
              className="note-card"
            >

              <h3>
                {note.title}
              </h3>

              <p>
                {note.message}
              </p>

            </div>

          ))

        )
        : (

          <p>
            No Notes Available
          </p>

        )

      }

    </div>

  );

}

export default NotesList;
